import base64

import streamlit as st
import streamlit.components.v1 as components

# ----------------------------------------------------------------------------
# COSMAX Package Hub
# ----------------------------------------------------------------------------
# The entire UI (hero parallax, filter chips, material tooltips, compare tray,
# compare modal, vendor directory page) is a self-contained single-page app.
# It is embedded here as a base64-encoded HTML string and rendered through
# streamlit.components.v1.html so its CSS *and* JavaScript run intact — no
# external .html/.csv/image files, everything lives in this app.py.
# ----------------------------------------------------------------------------

st.set_page_config(
    page_title="COSMAX Package Hub",
    page_icon="📦",
    layout="wide",
    initial_sidebar_state="collapsed",
)

# Strip Streamlit's default chrome/padding so the embedded app fills the viewport.
st.markdown(
    """
    <style>
      [data-testid="stHeader"], [data-testid="stToolbar"],
      [data-testid="stSidebar"], [data-testid="stSidebarCollapsedControl"],
      footer, #MainMenu {display: none !important;}
      [data-testid="stAppViewContainer"] > .main {padding: 0 !important;}
      [data-testid="stAppViewContainer"] {background: #F5F5F7;}
      .block-container {padding: 0 !important; margin: 0 !important; max-width: 100% !important;}
      [data-testid="stVerticalBlock"] {gap: 0 !important;}
      [data-testid="stMainBlockContainer"] {padding: 0 !important;}
      /* Make the embedded component fill the full browser viewport */
      .stApp iframe {width: 100% !important; height: 100vh !important; border: none;}
      div:has(> iframe) {height: 100vh !important; line-height: 0;}
      [data-testid="stCustomComponentV1"] {height: 100vh !important;}
    </style>
    """,
    unsafe_allow_html=True,
)

_HTML_B64 = ""

_HTML = base64.b64decode(_HTML_B64).decode("utf-8")

# height is the initial hint; the CSS above stretches the iframe to 100vh.
components.html(_HTML, height=1000, scrolling=True)
